export function getEmpreendimentos() {
  return [
    {
      id: 1,
      nome: 'Alto da Alvorada',
      slug: 'alto-da-alvorada',
      descricao: 'Empreendimento residencial de alto padrão com 95 unidades distribuídas em 1 bloco',
      logo: '/logo-qb.png',
      totalUnidades: ALTO_DA_ALVORADA.length
    },
    {
      id: 2,
      nome: 'Alto do Horizonte',
      slug: 'alto-do-horizonte',
      descricao: 'Empreendimento residencial de alto padrão com 344 unidades distribuídas em 4 blocos',
      logo: '/logo-qb.png',
      totalUnidades: ALTO_DO_HORIZONTE.length
    }
  ];
}

export function getUnidadesByEmpreendimento(empreendimento: string) {
  switch (empreendimento) {
    case 'alto-da-alvorada':
      return ALTO_DA_ALVORADA;
    case 'alto-do-horizonte':
      return ALTO_DO_HORIZONTE;
    default:
      return [];
  }
}

export function getFiltrosDisponiveis(empreendimento: string) {
  const unidades = getUnidadesByEmpreendimento(empreendimento);
  
  if (unidades.length === 0) {
    return { blocos: [], andares: [], disponibilidades: [], posicoesSol: [], tipologias: [] };
  }

  const blocos = Array.from(new Set(unidades.map(u => u.unidade.charAt(0)))).sort();
  const andares = Array.from(new Set(unidades.map(u => u.andar))).sort((a, b) => a - b);
  const disponibilidades = Array.from(new Set(unidades.map(u => u.disponibilidade))).sort();
  const posicoesSol = Array.from(new Set(unidades.map(u => u.posicaoSol))).sort();
  const tipologias = Array.from(new Set(unidades.map(u => u.tipologia))).sort();

  return {
    blocos,
    andares,
    disponibilidades,
    posicoesSol,
    tipologias
  };
}
